  SELECT DECODE(SEX,'Α','ΤΟΥ ΘΑΝΟΝΤΟΣ','Θ','ΤΗΣ ΘΑΝΟΥΣΗΣ')
  INTO V_SEX
  FROM REG_INSURED 
  WHERE INSURED_ID = :P_INSURED_ID;
  
  RETURN V_SEX;
end;

      function CF_INSURED_IND_PLUS65Formula return Date is
 V_BIRTH_DATE DATE;
begin
  /*FIND INDIRECT MEMBER DATE OF DEATH +  65 YEARS*/
  SELECT DATE_OF_BIRTH
  INTO V_BIRTH_DATE
  FROM REG_INSURED A
  WHERE A.INSURED_ID = :P_INSURED_ID_IND;
 
  RETURN ADD_MONTHS(V_BIRTH_DATE,65*12);
 
end;

      function CF_COMPARE_DATESFormula return Char is
 
 V_CHAR VARCHAR2(10);
 
begin
  IF :CF_INSURED_IND_PLUS65  <= :CF_TERMINATION_TRI_YEARS THEN 
      V_CHAR := '30%';
  ELSIF :CF_INSURED_IND_PLUS65  > :CF_TERMINATION_TRI_YEARS THEN
  	  V_CHAR := '50%';
  END IF;
  
  RETURN V_CHAR;
end;

      FUNCTION CF_PERSON_NAMEFormula RETURN CHAR IS

 v_Psv_user_id VARCHAR2(15);
 V_PERSON_NAME VARCHAR2(100);

Cursor cur_Psv_user_id is 
SELECT Created_By
FROM PEN_DECISION_INSTANCE
WHERE  PEN_DECISION_INSTANCE.Dec_Incr_Seq_No=:P_DECISION_NO
AND PEN_DECISION_INSTANCE.Dt_Dec_Unit_Code=:P_Dt_Dec_Unit_Code
AND PEN_DECISION_INSTANCE.Dt_Decision_Year=:P_Dt_Decision_Year
