cursor Cur_Fact_Subtype_Existance_2 IS select distinct pen_dec_fact_types_instance.value from pen_dec_fact_types_instance WHERE pen_dec_fact_types_instance.title_code='00069' AND pen_dec_fact_types_instance.ins_insured_id= :P_INSURED_ID_IND AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1' AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND pen_dec_fact_types_instance.dec_fact_type_code = '00584';
cursor Cur_Fact_Subtype_Existance_3 IS select distinct pen_dec_fact_types_instance.value from pen_dec_fact_types_instance WHERE pen_dec_fact_types_instance.title_code='01069' AND pen_dec_fact_types_instance.ins_insured_id= :P_INSURED_ID_IND AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1' AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND pen_dec_fact_types_instance.dec_fact_type_code = '00584' UNION select distinct pen_dec_fact_types_instance.value ---EE-DS from pen_dec_fact_types_instance WHERE pen_dec_fact_types_instance.title_code='99111' AND pen_dec_fact_types_instance.ins_insured_id= :P_INSURED_ID_IND AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1' AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND pen_dec_fact_types_instance.dec_fact_type_code = '00584' ;
V_DEATH_REASON VARCHAR2(20); begin to_return :=''; v_iban := null; open Cur_Fact_Subtype_Existance; fetch Cur_Fact_Subtype_Existance into v_iban; close Cur_Fact_Subtype_Existance;
