     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '01367' AND
	     A.Dec_Fact_Type_Code = '00661';

  OPEN cur_INS_AVERAGE_INCOME;
  FETCH cur_INS_AVERAGE_INCOME
  INTO V_AVERAGE_INCOME;
  CLOSE cur_INS_AVERAGE_INCOME;

	IF V_AK IS NOT NULL THEN 
		V_RESULT := V_AK;
	ELSIF V_AVERAGE_INCOME IS NOT NULL THEN
		V_RESULT := V_AVERAGE_INCOME;
	END IF;

*/
begin

  OPEN cur_INS_CLASS_25PLASIO;
  FETCH cur_INS_CLASS_25PLASIO
  INTO V_AK_25PLASIO;
  CLOSE cur_INS_CLASS_25PLASIO;
  
	V_RESULT := V_AK_25PLASIO;

  RETURN V_RESULT;
  
end;

