function CF_29Formula return VARCHAR2 is v_date_char varchar2(10); v_ymd varchar2(100); begin v_date_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id, :P_DT_DECISION_YEAR_DIR, :P_DT_DEC_UNIT_CODE_DIR, :P_DT_INCR_SEC_NO_DIR, '1', 0, 0, '1', '00639', '00684');
if nvl(v_date_char,'0') = '0' then v_date_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id, :P_DT_DECISION_YEAR_DIR, :P_DT_DEC_UNIT_CODE_DIR, :P_DT_INCR_SEC_NO_DIR, '1', 0, 0, '1', '00638', '00677'); end if;
v_ymd := nvl(v_date_char,'0')||'-';
v_date_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id, :P_DT_DECISION_YEAR_DIR, :P_DT_DEC_UNIT_CODE_DIR, :P_DT_INCR_SEC_NO_DIR, '1', 0, 0, '1', '00639', '00685');
if nvl(v_date_char,'0') = '0' then v_date_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id, :P_DT_DECISION_YEAR_DIR, :P_DT_DEC_UNIT_CODE_DIR, :P_DT_INCR_SEC_NO_DIR, '1', 0, 0, '1', '00638', '00678'); end if;
v_ymd := v_ymd||nvl(v_date_char,'0')||'-';
v_date_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id, :P_DT_DECISION_YEAR_DIR, :P_DT_DEC_UNIT_CODE_DIR, :P_DT_INCR_SEC_NO_DIR, '1', 0, 0, '1', '00639', '00686');
if nvl(v_date_char,'0') = '0' then v_date_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id, :P_DT_DECISION_YEAR_DIR, :P_DT_DEC_UNIT_CODE_DIR, :P_DT_INCR_SEC_NO_DIR, '1', 0, 0, '1', '00638', '00679'); end if;
v_ymd := v_ymd||nvl(v_date_char,'0');
return v_ymd;
end;

